// 'class1'というクラスを持つ全ての要素に'class2'というクラスを追加します。
let elements = document.getElementsByClassName('class1');
for(let i = 0; i < elements.length; i++) {
    elements[i].classList.add('class2');
}
// このコードを実行すると、'class1'というクラスを持つ全ての要素に'class2'が追加されます。

// 'class1'というクラスを持つ全ての要素から'class1'というクラスを削除します。
let elements = document.getElementsByClassName('class1');
while(elements[0]) {
    elements[0].classList.remove('class1');
}
// このコードを実行すると、'class1'というクラスを持つ全ての要素から'class1'が削除されます。

// 'class1'というクラスを持つ全ての要素で'class1'というクラスの有無を切り替えます。
let elements = document.getElementsByClassName('class1');
for(let i = 0; i < elements.length; i++) {
    elements[i].classList.toggle('class1');
}
// このコードを実行すると、'class1'というクラスを持つ全ての要素で'class1'の有無が切り替わります。

// 'class1'と'class2'というクラスを両方持つ要素の数を取得します。
let elements = document.querySelectorAll('.class1.class2');
console.log(elements.length);
// このコードを実行すると、コンソールに'class1'と'class2'を両方持つ要素の数が表示されます。

// 'class1'というクラスを持つ全ての要素が'class2'というクラスを持っているかを判定します。
let elements = document.getElementsByClassName('class1');
for(let i = 0; i < elements.length; i++) {
    console.log(elements[i].classList.contains('class2'));
}
// このコードを実行すると、コンソールに各要素が'class2'を持っているかの判定結果（trueまたはfalse）が表示されます。

// 'class1'というクラスを持つ全ての要素について、'class2'というクラスを持つ要素は'class2'を削除し、持たない要素は'class2'を追加します。
let elements = document.getElementsByClassName('class1');
for(let i = 0; i < elements.length; i++) {
    if(elements[i].classList.contains('class2')) {
        elements[i].classList.remove('class2');
    } else {
        elements[i].classList.add('class2');
    }
}
// このコードを実行すると、'class1'というクラスを持つ全ての要素で'class2'の有無が適切に切り替わります。

// 'element'というIDを持つ要素のクラス名をすべて取得します。
let element = document.getElementById('element');
console.log(element.className);
// このコードを実行すると、コンソールに'element'というIDを持つ要素のクラス名が表示されます。

// 'element'というIDを持つ要素のクラス名をすべて'newClass'に変更します。
let element = document.getElementById('element');
element.className = 'newClass';
// このコードを実行すると、'element'というIDを持つ要素のクラス名がすべて'newClass'に変更されます。

// 'id1'というidを持つ要素が'class1'というクラスを持つかどうかを確認します。
let element = document.getElementById('id1');
console.log(element.classList.contains('class1'));
// このコードを実行すると、コンソールに'id1'というidを持つ要素が'class1'というクラスを持つかどうかの結果が表示されます。

// 'id1'というidを持つ要素に'class1', 'class2', 'class3'の3つのクラスを追加します。
let element = document.getElementById('id1');
element.classList.add('class1', 'class2', 'class3');
// このコードを実行すると、'id1'というidを持つ要素に'class1', 'class2', 'class3'の3つのクラスが追加されます。
